__d(function(a,e,o,s,l,r,n){l.exports={yo_nunca:{nombre:"Yo Nunca",como_se_juega:"Por turnos, el jugador en pantalla lee la carta en voz alta. Todos los que S\xcd lo hayan hecho alguna vez, beben un trago. Quien pase de responder, bebe 2.",reglas_especiales:["Prohibido mentir: si te pillan, bebes el doble","Si nadie del grupo lo ha hecho, bebe quien ley\xf3 la carta","En modo aleatorio, el punto de color de la esquina indica el nivel de la carta"],como_se_juega_chill:"Por turnos, el jugador en pantalla lee la carta en voz alta. Todos los que S\xcd lo hayan hecho alguna vez, suman un punto. Quien pase de responder, suma 2 puntos.",reglas_especiales_chill:["Prohibido mentir: si te pillan, sumas el doble","Si nadie del grupo lo ha hecho, suma un punto quien ley\xf3 la carta","En modo aleatorio, el punto de color de la esquina indica el nivel de la carta"]},comandante:{nombre:"Comandante",como_se_juega:"Por turnos se revela una carta y se cumple lo que ordena, sin discutir. Hay 7 tipos de carta y la intensidad sube sola a medida que avanza el mazo.",reglas_especiales:["Las REGLAS quedan activas (m\xe1ximo 5): se ven arriba del todo y se cumplen hasta que se eliminen","Los PODERES se guardan en mano (m\xe1ximo 1 por jugador): toca el nombre de un jugador para ver o usar el suyo. Guardar uno nuevo sustituye al anterior","Las alianzas comparten tragos y se ven en los nombres; una carta que rompe una alianza sin que haya ninguna activa hace beber 2 a quien la sac\xf3","Si rechazas un duelo, bebes el doble"],reglas_especiales_chill:["Las REGLAS quedan activas (m\xe1ximo 5): se ven arriba del todo y se cumplen hasta que se eliminen","Los PODERES se guardan en mano (m\xe1ximo 1 por jugador): toca el nombre de un jugador para ver o usar el suyo. Guardar uno nuevo sustituye al anterior","Las alianzas comparten puntos y se ven en los nombres; una carta que rompe una alianza sin que haya ninguna activa hace sumar 2 a quien la sac\xf3","Si rechazas un duelo, sumas el doble"]},rey_de_la_copa:{nombre:"Rey de la Copa",como_se_juega:"Se van volteando cartas una a una. Cada valor tiene una regla fija. Los Reyes son los m\xe1s peligrosos \u2014 van acumulando tragos hasta que el cuarto Rey pone fin al juego.",reglas_especiales:["As: inventa una regla que todos deben cumplir. Romperla = bebe 2","8: elige un compa\xf1ero de bebida para el resto de la partida","Rey: 1\xba bebe 2 \xb7 2\xba bebe 4 \xb7 3\xba bebe 4 y reparte 2 \xb7 4\xba bebe 4 y reparte 4 \u2014 fin del juego"],como_se_juega_chill:"Se van volteando cartas una a una. Cada valor tiene una regla fija. Los Reyes son los m\xe1s peligrosos \u2014 van acumulando puntos hasta que el cuarto Rey pone fin al juego.",reglas_especiales_chill:["As: inventa una regla que todos deben cumplir. Romperla = suma 2 puntos","8: elige un compa\xf1ero de fatigas para el resto de la partida","Rey: 1\xba suma 2 puntos \xb7 2\xba suma 4 puntos \xb7 3\xba suma 4 puntos y reparte 2 \xb7 4\xba suma 4 puntos y reparte 4 \u2014 fin del juego"]},carrera_de_caballos:{nombre:"Carrera de Caballos",como_se_juega:"Cada jugador apuesta sus chupitos a un caballo. Se lanza la carrera y sale un ganador aleatorio. Quien falla bebe sus chupitos. Quien acierta reparte el DOBLE de lo que apost\xf3: elige a qui\xe9n mandar beber.",reglas_especiales:["M\xednimo 1 chupito por jugador, m\xe1ximo 10","Quien acierta reparte el doble de lo apostado (apost\xf3 3 \u2192 reparte 6) entre quien quiera","Tras la carrera, cada acertante toca a qui\xe9n manda beber para llevar la cuenta","El ganador es aleatorio \u2014 nadie sabe qui\xe9n va a ganar hasta el final"],como_se_juega_chill:"Cada jugador apuesta sus puntos a un caballo. Se lanza la carrera y sale un ganador aleatorio. Quien falla suma un punto sus puntos. Quien acierta reparte el DOBLE de lo que apost\xf3: elige a qui\xe9n mandar sumar.",reglas_especiales_chill:["M\xednimo 1 punto por jugador, m\xe1ximo 10","Quien acierta reparte el doble de lo apostado (apost\xf3 3 \u2192 reparte 6) entre quien quiera","Tras la carrera, cada acertante toca a qui\xe9n manda sumar para llevar la cuenta","El ganador es aleatorio \u2014 nadie sabe qui\xe9n va a ganar hasta el final"]},la_bomba:{nombre:"La Bomba",como_se_juega:"El m\xf3vil es una bomba con mecha. Sale una categor\xeda y, por turnos, cada uno dice algo de esa categor\xeda y pasa el m\xf3vil (a mano) antes de que explote. La categor\xeda dura hasta que explota; a quien le pille, bebe.",reglas_especiales:["El tiempo es aleatorio entre 20 y 60 segundos \u2014 nadie sabe cu\xe1ndo explota","Los tragos son aleatorios entre 1 y 5 \u2014 tampoco sabes cu\xe1nto beber\xe1s si explota","Cuando la mecha est\xe1 muy corta, el borde se pone rojo \u2014 \xa1date prisa!","Al explotar, el grupo marca a qui\xe9n le pill\xf3 para llevar la cuenta"],como_se_juega_chill:"El m\xf3vil es una bomba con mecha. Sale una categor\xeda y, por turnos, cada uno dice algo de esa categor\xeda y pasa el m\xf3vil (a mano) antes de que explote. La categor\xeda dura hasta que explota; a quien le pille, suma un punto.",reglas_especiales_chill:["El tiempo es aleatorio entre 20 y 60 segundos \u2014 nadie sabe cu\xe1ndo explota","Los puntos son aleatorios entre 1 y 5 \u2014 tampoco sabes cu\xe1nto sumar\xe1s si explota","Cuando la mecha est\xe1 muy corta, el borde se pone rojo \u2014 \xa1date prisa!","Al explotar, el grupo marca a qui\xe9n le pill\xf3 para llevar la cuenta"]},cinco_segundos:{nombre:"5 Segundos",como_se_juega:"Sale una categor\xeda. El jugador en turno tiene 5 segundos para nombrar 3 cosas de esa categor\xeda sin repetirse ni quedarse en blanco. El grupo decide si lo ha conseguido.",reglas_especiales:["Si no lo consigue, bebe 1","El jugador puede pulsar 'He terminado' antes de tiempo"],reglas_especiales_chill:["Si no lo consigue, suma 1 punto","El jugador puede pulsar 'He terminado' antes de tiempo"]},mayor_o_menor:{nombre:"Mayor o Menor",como_se_juega:"Sale una carta. El jugador en turno predice si la siguiente carta del mazo ser\xe1 mayor o menor. Si acierta, no bebe. Si falla, bebe 1. Si sale el mismo valor, todos beben 1.",reglas_especiales:["El As vale como el valor m\xe1s bajo (1)","J, Q, K valen 11, 12 y 13 respectivamente"],como_se_juega_chill:"Sale una carta. El jugador en turno predice si la siguiente carta del mazo ser\xe1 mayor o menor. Si acierta, no suma un tanto. Si falla, suma 1 tanto. Si sale el mismo valor, todos suman 1 tanto."},verdad_o_reto:{nombre:"Verdad o Reto",como_se_juega:"En tu turno elige Verdad o Reto. En una Verdad el grupo decide si dijiste la verdad o mentiste; si minti\xf3, bebe. En un Reto, lo cumple o bebe. Pulsa el bot\xf3n que corresponda para pasar el turno.",reglas_especiales:["Si eliges lo mismo 3 veces seguidas, la pr\xf3xima vez te toca la otra opci\xf3n","Verdad: dos botones \u2014 'Dijo la verdad' (pasa) o 'Minti\xf3 \xb7 bebe'","Reto: dos botones \u2014 'Cumpli\xf3 el reto' (pasa) o 'No lo hizo \xb7 bebe'","Puedes 'Saltar carta' para descartarla sin que nadie beba"],como_se_juega_chill:"En tu turno elige Verdad o Reto. En una Verdad el grupo decide si dijiste la verdad o mentiste; si minti\xf3, suma un punto. En un Reto, lo cumple o suma un punto. Pulsa el bot\xf3n que corresponda para pasar el turno.",reglas_especiales_chill:["Si eliges lo mismo 3 veces seguidas, la pr\xf3xima vez te toca la otra opci\xf3n","Verdad: dos botones \u2014 'Dijo la verdad' (pasa) o 'Minti\xf3 \xb7 suma un punto'","Reto: dos botones \u2014 'Cumpli\xf3 el reto' (pasa) o 'No lo hizo \xb7 suma un tanto'","Puedes 'Saltar carta' para descartarla sin que nadie beba"]},mimica:{nombre:"M\xedmica",como_se_juega:"Por equipos. Un jugador ve una palabra y la act\xfaa sin hablar ni hacer sonidos. Su equipo intenta adivinarla en 60 segundos. Cada acierto suma un punto.",reglas_especiales:["No se pueden decir palabras ni hacer sonidos, solo gestos","El equipo con menos puntos al final bebe seg\xfan la diferencia de puntuaci\xf3n"],reglas_especiales_chill:["No se pueden decir palabras ni hacer sonidos, solo gestos","El equipo con menos puntos al final suma un punto seg\xfan la diferencia de puntuaci\xf3n"]},alias:{nombre:"Alias",como_se_juega:"Por equipos. Un jugador ve una palabra y tiene que describirla con otras palabras para que su equipo la adivine en 60 segundos. No puede decir la palabra principal ni las 3 palabras prohibidas que aparecen junto a ella.",reglas_especiales:["Si el jugador dice la palabra principal o una prohibida, el otro equipo puede marcarlo y se pierde esa palabra","El equipo con menos puntos al final bebe seg\xfan la diferencia de puntuaci\xf3n"],reglas_especiales_chill:["Si el jugador dice la palabra principal o una prohibida, el otro equipo puede marcarlo y se pierde esa palabra","El equipo con menos puntos al final suma un punto seg\xfan la diferencia de puntuaci\xf3n"]},oca_borracha:{nombre:"Oca Borracha",como_se_juega:"Tablero de 45 casillas. Tira el dado y avanza tu ficha. Cada casilla tiene una acci\xf3n o castigo. El primero en llegar a la casilla 45 gana, pero bebe 5 chupitos.",reglas_especiales:["La casilla 34 (PUTAD\xd3N) te devuelve al inicio","Algunas casillas te hacen avanzar o retroceder autom\xe1ticamente","Pod\xe9is seguir jugando tras el primer ganador o terminar la partida"],como_se_juega_chill:"Tablero de 45 casillas. Tira el dado y avanza tu ficha. Cada casilla tiene una acci\xf3n o castigo. El primero en llegar a la casilla 45 gana, pero suma 5 tantos."},el_impostor:{nombre:"El Impostor",como_se_juega:"Todos reciben la misma palabra excepto el impostor, que recibe una palabra distinta de la misma categor\xeda. Por turnos, cada uno da una pista sin decir la palabra. Al final, vot\xe1is qui\xe9n cre\xe9is que es el impostor.",reglas_especiales:["M\xednimo 3 jugadores","Si acert\xe1is qui\xe9n es el impostor, \xe9l bebe. Si fall\xe1is, el impostor reparte tragos entre todos"],reglas_especiales_chill:["M\xednimo 3 jugadores","Si acert\xe1is qui\xe9n es el impostor, \xe9l suma un punto. Si fall\xe1is, el impostor reparte puntos entre todos"]},parchis_borracho:{nombre:"Parch\xeds Borracho",como_se_juega:"Cada jugador tiene 2 fichas de su color. Necesitas sacar un 5 para salir de casa. Avanza seg\xfan el dado y come las fichas rivales que pilles en el camino. El primero en llevar sus 2 fichas a la meta gana.",reglas_especiales:["Las casillas especiales cambian en cada partida \u2014 nunca hay dos tableros iguales","Si te comen una ficha, bebes. El que te come reparte un trago extra","Si pasan 3 turnos sin sacar el 5 de salida, bebes 1 por la frustraci\xf3n"],reglas_especiales_chill:["Las casillas especiales cambian en cada partida \u2014 nunca hay dos tableros iguales","Si te comen una ficha, sumas un tanto. El que te come reparte un punto extra","Si pasan 3 turnos sin sacar el 5 de salida, sumas 1 punto por la frustraci\xf3n"]},la_piramide:{nombre:"La Pir\xe1mide",como_se_juega:"Se forma una pir\xe1mide de cartas boca abajo. Antes de revelar cada carta el grupo decide: Beber o Pasar. Si bebes, los que tengan el mismo n\xfamero beben. Si pasas, los que tengan el mismo n\xfamero dan su carta a otro jugador y ese bebe.",reglas_especiales:["Si coincide el n\xfamero Y el palo, se beben el doble de tragos","Al pasar una carta, el jugador elige a qui\xe9n se la da \u2014 el que la recibe bebe","M\xe1ximo 7 cartas por jugador","La primera fila vale 1 trago, la \xfaltima vale 5 tragos"],como_se_juega_chill:"Se forma una pir\xe1mide de cartas boca abajo. Antes de revelar cada carta el grupo decide: sumar o Pasar. Si sumas un tanto, los que tengan el mismo n\xfamero suman un tanto. Si pasas, los que tengan el mismo n\xfamero dan su carta a otro jugador y ese suma un tanto.",reglas_especiales_chill:["Si coincide el n\xfamero Y el palo, se suman el doble de puntos","Al pasar una carta, el jugador elige a qui\xe9n se la da \u2014 el que la recibe suma un tanto","M\xe1ximo 7 cartas por jugador","La primera fila vale 1 punto, la \xfaltima vale 5 puntos"]},ruleta_borracha:{nombre:"Ruleta Borracha",como_se_juega:"Cada jugador apuesta sus chupitos a un n\xfamero, color, par o impar. Se gira la ruleta y seg\xfan el resultado, los que aciertan reparten y los que fallan beben.",reglas_especiales:["Acertar el n\xfamero exacto \u2192 repartes el triple","Acertar el color \u2192 repartes el doble","Acertar par/impar \u2192 repartes lo apostado","Si sale el 0 verde \u2192 todos beben lo apostado sin excepci\xf3n"],como_se_juega_chill:"Cada jugador apuesta sus puntos a un n\xfamero, color, par o impar. Se gira la ruleta y seg\xfan el resultado, los que aciertan reparten y los que fallan suman un tanto.",reglas_especiales_chill:["Acertar el n\xfamero exacto \u2192 repartes el triple","Acertar el color \u2192 repartes el doble","Acertar par/impar \u2192 repartes lo apostado","Si sale el 0 verde \u2192 todos suman un punto lo apostado sin excepci\xf3n"]},triman:{nombre:"Triman",como_se_juega:"Tira los dados. El primero en sacar suma 3 se convierte en el Triman. A partir de ah\xed, cada vez que alguien saque un 3, el Triman bebe. Sigues tirando mientras saques resultados con efecto.",reglas_especiales:["Suma 7 \u2014 bebe el de tu derecha","Suma 9 \u2014 bebe el de tu izquierda","Suma 11 \u2014 bebe toda la mesa","Dobles \u2014 repartes los tragos como quieras","El Triman solo se libera sacando un 3 en su propio turno"],como_se_juega_chill:"Tira los dados. El primero en sacar suma 3 se convierte en el Triman. A partir de ah\xed, cada vez que alguien saque un 3, el Triman suma un punto. Sigues tirando mientras saques resultados con efecto.",reglas_especiales_chill:["Suma 7 \u2014 suma un punto el de tu derecha","Suma 9 \u2014 suma un punto el de tu izquierda","Suma 11 \u2014 suma un strike toda la mesa","Dobles \u2014 repartes los puntos como quieras","El Triman solo se libera sacando un 3 en su propio turno"]},polis_y_cacos:{nombre:"Polis y Cacos",como_se_juega:"Hay un Asesino, un Polic\xeda y el resto son Ciudadanos. El Asesino mata en silencio con un gui\xf1o; a quien le gui\xf1en, pulsa su propio nombre. El Polic\xeda tiene una sola oportunidad para acusar. Si el Asesino mata a todos los Ciudadanos antes de ser descubierto, gana \xe9l.",reglas_especiales:["M\xednimo 5 jugadores","Cada jugador asesinado bebe 2 tragos","Si el Polic\xeda atrapa al Asesino, este bebe 4 tragos","Si el Polic\xeda acusa mal, la ronda acaba y bebe 3 tragos","Si el Asesino mata al Polic\xeda, se delata: pierde la partida y bebe 4 tragos"],reglas_especiales_chill:["M\xednimo 5 jugadores","Cada jugador asesinado suma 2 strikes","Si el Polic\xeda atrapa al Asesino, este suma 4 tantos","Si el Polic\xeda acusa mal, la ronda acaba y suma 3 puntos","Si el Asesino mata al Polic\xeda, se delata: pierde la partida y suma 4 strikes"]}}},831,[]);
